#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>

uint8_t g_function(uint8_t a, uint8_t b, uint8_t x) {
    uint8_t temp = (a + b + x) & 0xFF;
    return ((temp << 2) | (temp >> 6)) & 0xFF;
}

uint32_t f_function(uint32_t input_val) {
    uint8_t x[4], y[4];
    uint32_t val = input_val;
    for (int i = 0; i < 4; i++) {
        x[i] = val & 0xFF;
        val >>= 8;
    }
    y[2] = g_function(x[3] ^ x[2], x[1] ^ x[0], 1);
    y[3] = g_function(x[3], y[2], 0);
    y[1] = g_function(x[1] ^ x[0], y[2], 0);
    y[0] = g_function(x[0], y[1], 1);
    uint32_t output = 0;
    for (int i = 0; i < 4; i++) {
        output |= (uint32_t)y[i] << (8 * i);
    }
    return output;
}

int main() {
    unsigned char *seen = calloc(1ULL << 28, 1); // 256MB - too large
    // Actually let's just test a smaller sample
    printf("Testing F function properties...\n");

    // Check if specific patterns hold
    // For a Feistel-like cipher, we need to see if F can be linearized
    printf("f(0) = 0x%08X\n", f_function(0));
    printf("f(0xFFFFFFFF) = 0x%08X\n", f_function(0xFFFFFFFF));
    printf("f(0x12345678) = 0x%08X\n", f_function(0x12345678));

    // Check if the expand function is invertible
    printf("\nChecking expand function collisions...\n");
    unsigned int *exp = calloc(1 << 20, sizeof(unsigned int));
    for (int i = 0; i < (1<<20); i++) {
        uint32_t e = i ^ (i << 16) ^ (i * 12345);
        exp[i] = e;
    }
    // Check for collisions
    for (int i = 0; i < (1<<20); i++) {
        for (int j = i+1; j < (1<<20); j++) {
            if (exp[i] == exp[j]) {
                printf("Collision: %d and %d both give 0x%08X\n", i, j, exp[i]);
            }
        }
        if (i % 100000 == 0) printf("  Collision check: %d/%d\n", i, 1<<20);
    }
    printf("Collision check complete\n");

    free(exp);
    return 0;
}
